@@ -731,0 +729,18 @@
+  if (UseCompactObjectHeaders && !is_aligned(base_off, BytesPerLong)) {
+    guarantee(is_aligned(base_off, BytesPerInt), "must be 4-bytes aligned");
+    // The optimized copy routine only copies 8-byte words. For this reason, we must
+    // copy the 4 bytes at offset 4 separately.
+    Node* first = kit->gvn().transform(LoadNode::make(kit->gvn(), kit->control(), kit->memory(Compile::AliasIdxRaw),
+                                       kit->basic_plus_adr(src_base, base_off),
+                                       Compile::current()->get_adr_type(Compile::AliasIdxRaw), TypeInt::INT, T_INT,
+                                       MemNode::unordered));
+    Node* st = kit->gvn().transform(StoreNode::make(kit->gvn(), kit->control(), kit->memory(Compile::AliasIdxRaw),
+                                                    kit->basic_plus_adr(dst_base, base_off),
+                                                    Compile::current()->get_adr_type(Compile::AliasIdxRaw),
+                                                    first, T_INT, MemNode::unordered));
+    kit->set_memory(st, Compile::AliasIdxRaw);
+    kit->record_for_igvn(st);
+    base_off += sizeof(jint);
+    guarantee(is_aligned(base_off, BytesPerLong), "must be 8-bytes aligned");
+  }
